@app.post("/users")
def create_user():
    data = request.get_json(force=True, silent=False)
    email = (data.get("email") or "").strip().lower()
    if not email:
        raise BadRequest("email is required")
    username = data.get("username")
    if username is not None:
        username = str(username).strip()
        if username == "":
            username = None
    name = data.get("name")
    if name is not None:
        name = str(name).strip()
    bio = data.get("bio")
    if bio is not None:
        bio = str(bio)

    now = utcnow()
    doc = {
        "email": email,
        "username": username,
        "name": name,
        "bio": bio,
        "created_at": now,
        "updated_at": now,
        "meta": data.get("meta") if isinstance(data.get("meta"), dict) else {},
    }

    try:
        res = users.insert_one(doc)
    except DuplicateKeyError:
        raise BadRequest("email or username already exists")

    created = users.find_one({"_id": res.inserted_id})
    return jsonify(to_str_id(created)), 201

@app.get("/users")
def list_users():
    q = (request.args.get("q") or "").strip()
    limit = parse_int(request.args.get("limit"), default=20, min_value=1, max_value=200, field_name="limit")
    offset = parse_int(request.args.get("offset"), default=0, min_value=0, field_name="offset")
    sort = parse_sort(request.args.get("sort"), allowed_fields={"created_at", "updated_at", "email", "username", "name"})

    filter_ = {}
    if q:
        filter_ = {"$or": [
            {"email": {"$regex": q, "$options": "i"}},
            {"username": {"$regex": q, "$options": "i"}},
            {"name": {"$regex": q, "$options": "i"}},
        ]}

    cursor = users.find(filter_).sort(sort).skip(offset).limit(limit)
    items = [to_str_id(u) for u in cursor]
    total = users.count_documents(filter_)
    return jsonify({"items": items, "total": total, "limit": limit, "offset": offset})

