@app.get("/analytics/documents-by-status")
def documents_by_status():
    pipeline = [
        {"$group": {"_id": "$status", "count": {"$sum": 1}}},
        {"$project": {"_id": 0, "status": "$_id", "count": 1}},
        {"$sort": {"count": -1, "status": 1}},
    ]
    rows = list(documents.aggregate(pipeline))
    return jsonify({"items": rows})

@app.get("/analytics/top-tags")
def top_tags():
    limit = parse_int(request.args.get("limit"), default=20, min_value=1, max_value=200, field_name="limit")
    status = (request.args.get("status") or "").strip().lower()
    match = {}
    if status:
        if status not in ("draft", "published", "archived"):
            raise BadRequest("status must be one of: draft, published, archived")
        match["status"] = status

    pipeline = []
    if match:
        pipeline.append({"$match": match})
    pipeline += [
        {"$unwind": "$tags"},
        {"$group": {"_id": "$tags", "count": {"$sum": 1}}},
        {"$project": {"_id": 0, "tag": "$_id", "count": 1}},
        {"$sort": {"count": -1, "tag": 1}},
        {"$limit": limit},
    ]
    rows = list(documents.aggregate(pipeline))
    return jsonify({"items": rows, "limit": limit})

